/**
 * @param {string} microflowName
 * @param {MxObject} reqObject
 * @returns {Promise.<MxObject>}
 */
export async function ExecuteSubmitEsignTxnMicroflow(microflowName, reqObject) {
	// BEGIN USER CODE

	return new Promise(function(resolve, reject) {
		var reqObjectCopy = JSON.parse(JSON.stringify(reqObject));
		mx.data.action({
			params: {
				applyto: "selection",
				actionname: microflowName,
				guids: [reqObjectCopy.guid]
			},
			callback: function(obj) {
				resolve(obj[0]);
			},
			error: function(err) {
				console.error(JSON.stringify(err))
				mx.data.create({
					entity: "EXCR_Commons.Notification",
					callback: function(notif) {
						notif.set("ErrorMsg",err.message);
						notif.set("IsSuccessMsg",false);
						resolve(notif);
					},
					error: function(e) {
						console.error("Could not create notification obj:", e);
						resolve(null)
					}
				});
			}
		});
	});
	// END USER CODE
}
